  vereinsfarbe1:"#FFBF00", vereinsfarbe2:"#000000",
  navBg:"#000000", navText:"#FFFFFF", navAccent:null, navAccentText:null, navHover:"#1A1A1A", avatarBg:null, avatarText:null,
